SELECT a.account_id, l.loan_id
FROM account a
INNER JOIN loan l ON a.account_id = l.account_id;

SELECT e.event_name, b.remaining
FROM event e
INNER JOIN budget b ON e.event_id = b.link_to_event;

SELECT s.superhero_name
FROM superhero s
JOIN hero_power hp ON s.id = hp.hero_id
GROUP BY s.id
HAVING COUNT(hp.power_id) > 5;
/* Identifies superheroes with more than five unique powers */

SELECT s.superhero_name
FROM superhero s
JOIN hero_power hp ON s.id = hp.hero_id
GROUP BY s.id
HAVING COUNT(hp.power_id) > 3;
/* Identifies superheroes with more than three unique powers */
